import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-cv-builder',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './cv-builder.component.html',
  styleUrls: ['./cv-builder.component.css']
})
export class CvBuilderComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  cvData = {
    title: '',
    summary: '',
    skills: '',
    interests: '', // 🚀 Ajout du champ intérêts
    experiences: [] as any[],
    educations: [] as any[]
  };

  candidateName: string = '';
  avatarUrl: string | null = null;
  candidateContact = { email: '', phone: '', address: '' }; // 🚀 Infos perso du candidat
  successMessage: string = '';
  isSaving: boolean = false;

  ngOnInit() {
    this.candidateName = localStorage.getItem('name') || 'Candidat';
    this.fetchProfileDetails();
    this.fetchCurrentCV();
  }

  // 📥 CHARGEMENT DES INFOS PERSONNELLES (PHOTO + CONTACT)
  fetchProfileDetails() {
    const token = localStorage.getItem('token');
    fetch('http://localhost:3000/api/candidate/profile/details', {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => res.ok ? res.json() : null)
    .then(data => {
      if (data) {
        this.candidateContact.email = data.email || '';
        this.candidateContact.phone = data.phone || '';
        this.candidateContact.address = data.address || '';
        if (data.avatar_logo) {
          this.avatarUrl = `http://localhost:3000/logos/${data.avatar_logo}`;
        }
        this.cdr.detectChanges();
      }
    }).catch(() => {});
  }

  fetchCurrentCV() {
    const token = localStorage.getItem('token');
    fetch('http://localhost:3000/api/candidate/cv/details', {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => res.ok ? res.json() : null)
    .then(data => {
      if (data) {
        this.cvData.title = data.title || '';
        this.cvData.summary = data.summary || '';
        this.cvData.skills = data.skills || '';
        this.cvData.interests = data.interests || ''; // Mapping intérêts
        this.cvData.experiences = typeof data.experience === 'string' ? JSON.parse(data.experience) : (data.experience || []);
        this.cvData.educations = typeof data.education === 'string' ? JSON.parse(data.education) : (data.education || []);
        this.cdr.detectChanges();
      }
    }).catch(() => {});
  }

  addExperience() { this.cvData.experiences.push({ job_title: '', company: '', duration: '', description: '' }); this.cdr.detectChanges(); }
  removeExperience(index: number) { this.cvData.experiences.splice(index, 1); this.cdr.detectChanges(); }
  addEducation() { this.cvData.educations.push({ degree: '', school: '', year: '' }); this.cdr.detectChanges(); }
  removeEducation(index: number) { this.cvData.educations.splice(index, 1); this.cdr.detectChanges(); }

  getSkillsArray(): string[] { return this.cvData.skills ? this.cvData.skills.split(',').filter(s => s.trim() !== '') : []; }
  getInterestsArray(): string[] { return this.cvData.interests ? this.cvData.interests.split(',').filter(i => i.trim() !== '') : []; }

  onSaveCV(event: Event) {
    event.preventDefault();
    this.isSaving = true;
    const token = localStorage.getItem('token');
    
    const payload = {
      title: this.cvData.title,
      summary: this.cvData.summary,
      skills: this.cvData.skills,
      interests: this.cvData.interests, // Pousse les intérêts vers l'Update MySQL
      experience: JSON.stringify(this.cvData.experiences),
      education: JSON.stringify(this.cvData.educations)
    };

    fetch('http://localhost:3000/api/candidate/cv/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': token ? `Bearer ${token}` : '' },
      body: JSON.stringify(payload)
    })
    .then(res => res.ok ? res.json() : null)
    .then(() => {
      this.successMessage = "Votre CV a été enregistré avec succès !";
      this.isSaving = false;
      this.cdr.detectChanges();
      setTimeout(() => { this.successMessage = ''; this.cdr.detectChanges(); }, 3000);
    })
    .catch(() => { this.isSaving = false; this.cdr.detectChanges(); });
  }
}
<div class="cv-container-compact">
  
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-person-fill" style="color: #0ea5e9;"></i> Concepteur de CV Intelligent</h3>
      <p style="margin: 2px 0 0 0; color: #64748b; font-size: 13px;">Générez et prévisualisez votre structure de CV en temps réel.</p>
    </div>
  </div>

  @if (successMessage) {
    <div class="alert-box-compact alert-success">{{ successMessage }}</div>
  }

  <!-- 📊 GRILLE DE TRAVAIL DOUBLE PANNEAU -->
  <div class="cv-split-layout">
    
    <!-- ================= PANNEAU GAUCHE : FORMULAIRE DE SAISIE ================= -->
    <div class="cv-panel-card scrollable-form-panel">
      <form (ngSubmit)="onSaveCV($event)" class="compact-form-grid-vertical">
        
        <!-- Métier & Résumé -->
        <div class="form-section-title-inline"><i class="bi bi-person-badge"></i> Métier & Accroche</div>
        <div class="form-group-compact">
          <label>Titre du poste recherché *</label>
          <input type="text" name="cv_title" [(ngModel)]="cvData.title" placeholder="Ex: Développeur Fullstack Angular" required>
        </div>
        <div class="form-group-compact">
          <label>Résumé / Accroche professionnelle *</label>
          <textarea name="summary" [(ngModel)]="cvData.summary" rows="2" placeholder="Ex: Développeur motivé spécialisé dans..." required></textarea>
        </div>

        <!-- Compétences -->
        <div class="form-section-title-inline" style="margin-top: 10px;"><i class="bi bi-tags"></i> Compétences</div>
        <div class="form-group-compact">
          <label>Compétences clés (Séparées par des virgules) *</label>
          <input type="text" name="skills" [(ngModel)]="cvData.skills" placeholder="Ex: Angular, TypeScript, SQL, Docker" required>
        </div>

        <!-- Centres d'intérêt -->
        <div class="form-section-title-inline" style="margin-top: 10px;"><i class="bi bi-heart-fill"></i> Centres d'intérêt</div>
        <div class="form-group-compact">
          <label>Vos intérêts (Séparés par des virgules)</label>
          <input type="text" name="interests" [(ngModel)]="cvData.interests" placeholder="Ex: Lecture, Football, Gaming, Voyages">
        </div>

        <!-- Expériences Professionnelles Dynamiques -->
        <div class="form-section-title-inline-flex" style="margin-top: 10px;">
          <span><i class="bi bi-briefcase"></i> Expériences Professionnelles</span>
          <button type="button" class="btn-add-dynamic" (click)="addExperience()"><i class="bi bi-plus-circle-fill"></i> Ajouter</button>
        </div>
        
        @for (exp of cvData.experiences; track $index) {
          <div class="dynamic-entry-card">
            <div class="dynamic-entry-header">
              <span>Expérience #{{ $index + 1 }}</span>
              <button type="button" class="btn-remove-dynamic" (click)="removeExperience($index)"><i class="bi bi-trash3-fill"></i></button>
            </div>
            <div class="dynamic-fields-grid">
              <input type="text" name="exp_title_{{$index}}" [(ngModel)]="exp.job_title" placeholder="Poste (ex: Développeur)" required>
              <input type="text" name="exp_comp_{{$index}}" [(ngModel)]="exp.company" placeholder="Entreprise" required>
              <input type="text" name="exp_date_{{$index}}" [(ngModel)]="exp.duration" placeholder="Durée (ex: 2024 - Présent)" required>
              <textarea name="exp_desc_{{$index}}" [(ngModel)]="exp.description" rows="2" class="span-all-field" placeholder="Missions accomplies..." required></textarea>
            </div>
          </div>
        }

        <!-- Formations Dynamiques -->
        <div class="form-section-title-inline-flex" style="margin-top: 10px;">
          <span><i class="bi bi-mortarboard"></i> Formations & Études</span>
          <button type="button" class="btn-add-dynamic" (click)="addEducation()"><i class="bi bi-plus-circle-fill"></i> Ajouter</button>
        </div>

        @for (edu of cvData.educations; track $index) {
          <div class="dynamic-entry-card">
            <div class="dynamic-entry-header">
              <span>Formation #{{ $index + 1 }}</span>
              <button type="button" class="btn-remove-dynamic" (click)="removeEducation($index)"><i class="bi bi-trash3-fill"></i></button>
            </div>
            <div class="dynamic-fields-grid">
              <input type="text" name="edu_deg_{{$index}}" [(ngModel)]="edu.degree" placeholder="Diplôme (ex: Licence)" required>
              <input type="text" name="edu_sch_{{$index}}" [(ngModel)]="edu.school" placeholder="Université / École" required>
              <input type="text" name="edu_year_{{$index}}" [(ngModel)]="edu.year" placeholder="Année (ex: 2024)" required>
            </div>
          </div>
        }

        <div class="form-actions-compact">
          <button type="submit" class="btn-save-cv-compact" [disabled]="isSaving">
            <i class="bi bi-cloud-arrow-up-fill"></i> Enregistrer mon CV
          </button>
        </div>
      </form>
    </div>

    <!-- ================= PANNEAU DROIT : APERÇU ASYMÉTRIQUE ÉPURÉ ================= -->
    <div class="cv-panel-card preview-bg">
      <div class="cv-asymmetric-preview">
        
        <!-- 🗂️ COLONNE LATÉRALE SOMBRE (PHOTO, NOM, CONTACTS, INTÉRÊTS) -->
        <div class="cv-sidebar-preview">
          
          <div class="cv-avatar-wrapper">
            @if (avatarUrl) {
              <img [src]="avatarUrl" alt="Photo Candidat">
            } @else {
              <i class="bi bi-person-fill"></i>
            }
          </div>

          <div class="sidebar-info-block">
            <h4 class="cand-name-text">{{ candidateName }}</h4>
            <span class="cand-title-subtext">{{ cvData.title || 'Intitulé du poste' }}</span>
          </div>

          <div class="sidebar-contact-section">
            <div class="contact-line-preview"><i class="bi bi-envelope"></i> {{ candidateContact.email || 'Email non renseigné' }}</div>
            <div class="contact-line-preview"><i class="bi bi-telephone"></i> {{ candidateContact.phone || 'Téléphone non renseigné' }}</div>
            <div class="contact-line-preview"><i class="bi bi-geo-alt"></i> {{ candidateContact.address || 'Adresse non renseignée' }}</div>
          </div>

          <div class="sidebar-section-preview">
            <h6><i class="bi bi-heart"></i> Intérêts</h6>
            <div class="cv-interests-container">
              @if (cvData.interests) {
                @for (interest of getInterestsArray(); track interest) {
                  <span class="interest-tag-preview">{{ interest.trim() }}</span>
                }
              } @else {
                <span class="empty-text-italic">Aucun intérêt.</span>
              }
            </div>
          </div>

        </div>

        <!-- 📄 COLONNE PRINCIPALE BLANCHE (RÉSUMÉ, COMPÉTENCES, EXPÉRIENCES, FORMATIONS) -->
        <div class="cv-main-content-preview">
          
          <!-- Résumé -->
          <div class="main-section-preview">
            <h5 class="section-title-pro">Profil</h5>
            <p class="summary-text-pro">{{ cvData.summary || 'Votre résumé professionnel s\'affichera dans cette zone principale...' }}</p>
          </div>

          <!-- Compétences -->
          <div class="main-section-preview">
            <h5 class="section-title-pro">Compétences</h5>
            <div class="cv-tags-container">
              @if (cvData.skills) {
                @for (skill of getSkillsArray(); track skill) {
                  <span class="skill-tag-preview-pro">{{ skill.trim() }}</span>
                }
              } @else {
                <span class="empty-text-italic">Aucune compétence.</span>
              }
            </div>
          </div>

          <!-- Expériences -->
          <div class="main-section-preview">
            <h5 class="section-title-pro">Expériences Professionnelles</h5>
            @if (cvData.experiences.length > 0) {
              @for (exp of cvData.experiences; track exp) {
                <div class="preview-block-pro">
                  <div class="preview-row-pro">
                    <strong>{{ exp.job_title }}</strong>
                    <span class="date-tag-pro">{{ exp.duration }}</span>
                  </div>
                  <span class="sub-title-pro">{{ exp.company }}</span>
                  <p class="desc-text-pro">{{ exp.description }}</p>
                </div>
              }
            } @else {
              <span class="empty-text-italic">Aucune expérience renseignée.</span>
            }
          </div>

          <!-- Formations -->
          <div class="main-section-preview">
            <h5 class="section-title-pro">Éducation & Formations</h5>
            @if (cvData.educations.length > 0) {
              @for (edu of cvData.educations; track edu) {
                <div class="preview-block-pro">
                  <div class="preview-row-pro">
                    <strong>{{ edu.degree }}</strong>
                    <span class="date-tag-pro">{{ edu.year }}</span>
                  </div>
                  <span class="sub-title-pro">{{ edu.school }}</span>
                </div>
              }
            } @else {
              <span class="empty-text-italic">Aucune formation renseignée.</span>
            }
          </div>

        </div>

      </div>
    </div>

  </div>
</div>
